      "tahjeel_3": {
        "bookTitle": "ການສຶກສາ Hadith",
        "text": "hadiths ອ່ອນແອບໍ່ໄດ້ຖືກປະຕິບັດຕາມຄໍາຕັດສິນໂດຍສ່ວນໃຫຍ່. ເຂົາເຈົ້າອາດຈະຖືກປະຕິບັດໃນຄຸນງາມຄວາມດີດ້ວຍສາມເງື່ອນໄຂ."
      },
      "zawaid_abi_dawud_1": {
        "bookTitle": "Hadith ຂອງ Sunan ໄດ້",
        "text": "ປື້ມບັນທຶກຂອງ Sunan ແມ່ນໃນບັນດາຫນັງສືແມ່ຂອງ hadith. ຜູ້​ຂຽນ​ຈໍາ​ກັດ​ມັນ​ກັບ hadiths ກ່ຽວ​ກັບ​ການ​ຕັດ​ສິນ​. ສິ່ງ​ທີ່​ລາວ​ຍັງ​ມິດ​ງຽບ​ແມ່ນ​ສຽງ."
      },
      "zawaid_abi_dawud_2": {
        "bookTitle": "Hadith ຂອງ Sunan ໄດ້",
        "text": "ວິທະຍາສາດຂອງຂໍ້ບົກພ່ອງທີ່ເຊື່ອງໄວ້ແມ່ນຄວາມຊັດເຈນທີ່ສຸດຂອງວິທະຍາສາດ hadith. ມັນ ກຳ ນົດຂໍ້ບົກພ່ອງທີ່ລະອຽດອ່ອນທີ່ເຮັດໃຫ້ລະບົບຕ່ອງໂສ້ສຽງບໍ່ຖືກຕ້ອງ."
      },
      "ilal_tahara_1": {
        "bookTitle": "Purification Hadiths ຄໍາອະທິບາຍ",
        "text": "ທັດສະນະທີ່ຖືກຕ້ອງແມ່ນວ່າ wudu ກັບນ້ໍາທີ່ໃຊ້ແລ້ວແມ່ນອະນຸຍາດໄດ້ເນື່ອງຈາກການຂາດຫຼັກຖານສຽງທີ່ຫ້າມມັນ."
      },
      "ilal_tahara_2": {
        "bookTitle": "Purification Hadiths ຄໍາອະທິບາຍ",
        "text": "ການເຊັດໃສ່ຖົງຕີນແມ່ນສ້າງຕັ້ງຂຶ້ນໂດຍ mutawatir Sunnah. ໄລຍະເວລາຂອງມັນແມ່ນມື້ຫນຶ່ງແລະກາງຄືນສໍາລັບຜູ້ຢູ່ອາໄສແລະສາມສໍາລັບນັກທ່ອງທ່ຽວ."
      },
      "jami_uloom_1": {
        "bookTitle": "Compendium ຂອງຄວາມຮູ້ແລະປັນຍາ",
        "text": "ຄວາມຮູ້ທີ່ເປັນປະໂຫຍດແມ່ນສິ່ງທີ່ຕັ້ງຢູ່ໃນຫົວໃຈແລະຖືກປະຕິບັດໂດຍແຂນຂາ. ມັນພຽງພໍເປັນຄວາມຮູ້ທີ່ຈະຢ້ານກົວ Allah."
      },
      "jami_uloom_2": {
        "bookTitle": "Compendium ຂອງຄວາມຮູ້ແລະປັນຍາ",
        "text": "ສາດສະດາﷺໄດ້ກ່າວວ່າ: 'ຜູ້ໃດທີ່ເດີນຕາມເສັ້ນທາງໃນການຄົ້ນຫາຄວາມຮູ້, Allah ຈະໃຫ້ເສັ້ນທາງໄປສູ່ອຸທິຍານ.'"
      },
      "adhkar_sabah_1": {
        "bookTitle": "ຕອນເຊົ້າແລະຕອນແລງ Adhkar",
        "text": "ຕອນເຊົ້າ adhkar: 'ພວກເຮົາໄດ້ມາຮອດຕອນເຊົ້າແລະການປົກຄອງເປັນຂອງ Allah,' Ayat al-Kursi, Surahs Al-Ikhlas, Al-Falaq, ແລະ An-Nas."
      },
      "adhkar_sabah_2": {
        "bookTitle": "ຕອນເຊົ້າແລະຕອນແລງ Adhkar",
        "text": "ຜູ້ໃດທີ່ເວົ້າວ່າ Subhan Allah wa bihamdihi ຫນຶ່ງຮ້ອຍເທື່ອ, ບໍ່ມີໃຜຈະມາໃນວັນແຫ່ງການພິພາກສາທີ່ດີກ່ວາສິ່ງທີ່ເຂົາເອົາມາ."
      },
      "adhkar_masaa_1": {
        "bookTitle": "ຕອນເຊົ້າແລະຕອນແລງ Adhkar",
        "text": "ຕອນແລງ adhkar: 'ຂ້າພະເຈົ້າຊອກຫາບ່ອນລີ້ໄພໃນຄໍາເວົ້າທີ່ສົມບູນແບບຂອງ Allah ຈາກຄວາມຊົ່ວຮ້າຍຂອງສິ່ງທີ່ພຣະອົງໄດ້ສ້າງ' ສາມເທື່ອ, ແລະ Mu'awwidhat."
      },
      "adhkar_salat_1": {
        "bookTitle": "ຫລັງ​ການ​ອະ​ທິ​ຖານ Adhkar​",
        "text": "ຫຼັງ​ຈາກ​ການ​ອະ​ທິ​ຖານ​: ສະ​ແຫວງ​ຫາ​ການ​ໃຫ້​ອະ​ໄພ​ສາມ​ຄັ້ງ​, ຫຼັງ​ຈາກ​ນັ້ນ​ໃຫ້​ກຽດ​ສັກ​ສີ​, ສັນ​ລະ​ເສີນ​, ແລະ​ຍົກ​ສູງ​ລະ​ດັບ Allah ສາມ​ສິບ​ສາມ​ເທື່ອ​."
      },
      "adhkar_nawm_1": {
        "bookTitle": "ນອນ Adhkar",
        "text": "ນອນ adhkar: ຟັນກັບ Al-Ikhlas ແລະ Mu'awwidhat, ທ່ອງ Ayat al-Kursi, ແລະນອນເບື້ອງຂວາ."
      },
      "ruqyah_1": {
        "bookTitle": "Ruqyah ທາງ​ດ້ານ​ກົດ​ຫມາຍ​",
        "text": "ຂໍ້ Ruqyah: Al-Fatihah, Ayat al-Kursi, ຂໍ້ສຸດທ້າຍຂອງ Al-Baqarah, ແລະ Al-Ikhlas, Al-Falaq, An-Nas."
      },
      "ruqyah_2": {
        "bookTitle": "Ruqyah ທາງ​ດ້ານ​ກົດ​ຫມາຍ​",
        "text": "ຄໍາອ້ອນວອນຂອງ Ruqyah: 'ໃນພຣະນາມຂອງ Allah ຂ້າພະເຈົ້າປະຕິບັດ ruqyah ກັບເຈົ້າຈາກທຸກສິ່ງທຸກຢ່າງທີ່ເປັນອັນຕະລາຍຕໍ່ເຈົ້າ, ຈາກຄວາມຊົ່ວຮ້າຍຂອງຈິດວິນຍານຫຼືຕາທີ່ອິດສາ, Allah ປິ່ນປົວເຈົ້າ.'"
      },
      "resalah_azkar_1": {
        "bookTitle": "ສະຫຼຸບສັງລວມຂອງ Adhkar ແລະກົດລະບຽບ",
        "text": "ສາດສະດາ ﷺ ໄດ້ກ່າວວ່າ: 'ພວກຜູ້ນຳກ່ອນໜ້າ.' ເຂົາເຈົ້າຖາມວ່າ: 'ໃຜເປັນນາຍໜ້າ?' ພຣະອົງໄດ້ກ່າວວ່າ: 'ຜູ້ຊາຍແລະແມ່ຍິງຜູ້ທີ່ຈື່ Allah ອຸດົມສົມບູນ."
      }
